// Weekly reconciliation payload — the week's memories vs the current-truth layer.
const now = Date.now();
const weekAgo = now - 7 * 86400000;

const memoriesRaw = $('Get Recent Memories (week)').all().map(i => i.json).filter(m => m && m.memory_id);
const stateRaw    = $('Get Current State').all().map(i => i.json).filter(s => s && s.topic);
const decisionsRaw = $('Get Decisions Due').all().map(i => i.json).filter(d => d && d.decision_id);

const weekMemories = memoriesRaw.filter(m => new Date(m.created_at).getTime() >= weekAgo);

const payload = {
  week_ending_nz: new Date().toLocaleDateString('en-NZ', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Pacific/Auckland' }),
  memory_count_this_week: weekMemories.length,
  memories_this_week: weekMemories.slice(0, 60).map(m => ({
    date: (m.created_at || '').slice(0, 10),
    theme: (m.main_theme || m.summary || '').split('\n')[0].slice(0, 220),
  })),
  current_state: stateRaw.map(s => ({
    topic: s.topic,
    statement: (s.statement || '').slice(0, 400),
    status: s.status,
    updated: (s.updated_at || '').slice(0, 10),
  })),
  decisions_due_for_review: decisionsRaw.slice(0, 5).map(d => ({
    decision: d.decision_text,
    category: d.category || null,
    decided_on: (d.decision_date || '').slice(0, 10),
  })),
};

const system = `You are the background reconciler for Zane's Command Centre — the system that keeps his current-truth layer (current_state) honest without him lifting a finger. Once a week you read everything that happened and reconcile it against what the system currently believes is true.

Zane runs Moore AI Studios (AI solutions for NZ small businesses; live threads: Jake at Core Finance, Greenmachine, his own content/marketing, and this Command Centre system).

You get JSON: current_state (the canonical belief per topic, most recent first), memories_this_week (what actually happened, newest facts win), and decisions_due_for_review (past decisions whose outcome is still unrecorded).

Write a Telegram message using ONLY <b> and <i> tags. No markdown, no other tags. Under 3400 characters. Lead with one line: "Week reconciled — <the date>". Then these sections, each only if it has content:

<b>Truth to update</b> — topics in current_state that this week's memories contradict or move on. For each: the topic, then the corrected statement in one line. These are PROPOSALS for Zane to apply (or a Claude session to apply via update_current_state) — write them so they can be copied straight in.
<b>New threads</b> — anything significant this week not yet tracked as a current_state topic, worth adding.
<b>Contradictions</b> — places where the week's memories disagree with each other or with a decision, that a human should resolve.
<b>Decisions to close</b> — for each decisions_due_for_review item, one line phrased as a question inviting Zane to record the outcome (do NOT answer for him).
<b>Gone quiet</b> — active current_state topics with no mention at all this week (possible stalls or things to follow up).

Be specific and use real topic/client names. Never invent events. If a section is empty, omit its header. If the whole week is genuinely quiet, say so in one honest line rather than padding.`;

return [{
  json: {
    week_ending_nz: payload.week_ending_nz,
    anthropic_body: {
      model: 'claude-sonnet-5',
      max_tokens: 2000,
      thinking: { type: 'disabled' },
      system,
      messages: [{ role: 'user', content: JSON.stringify(payload) }],
    },
  },
}];

// Turn Claude's reconciliation into a Telegram digest + a memory note.
const CHECKIN_URL = 'https://cais-mcp-server.onrender.com/checkin?token=REPLACE_WITH_CHECKIN_TOKEN';

const res = $json;
let text = (res.content || [])
  .filter(b => b.type === 'text')
  .map(b => b.text)
  .join('\n')
  .trim();

if (!text) {
  text = '<b>Weekly reconciliation failed to generate</b> — check the reconciliation workflow execution log.';
}

const week = $('Build Reconciliation Payload').first().json.week_ending_nz;
const footer = `\n\n<a href="${CHECKIN_URL}">Open the check-in →</a>`;
const MAX = 4096 - footer.length - 20;
let message = text.length > MAX ? text.slice(0, MAX) + '…' : text;

return [{ json: { message: message + footer, memory_text: text, week_ending_nz: week } }];
